{"code": "import json
import re

# Load all books and reviews data from storage
books_file_path = locals()['var_functions.query_db:26']
reviews_file_path = locals()['var_functions.query_db:34']

# Read the JSON files
with open(books_file_path, 'r') as f:
    books_info = json.load(f)

with open(reviews_file_path, 'r') as f:
    reviews_data = json.load(f)

# Create mappings
books_dict = {book['book_id']: book for book in books_info}

# Process to find publication years and match with reviews
books_with_years = []
year_pattern = re.compile(r'(19|20)\d{2}')

for book in books_info:
    if book.get('details'):
        matches = year_pattern.findall(book['details'])
        if matches:
            # Take the first year found, convert to int
            try:
                year = int(matches[0])
                books_with_years.append({
                    'book_id': book['book_id'],
                    'title': book['title'],
                    'year': year,
                    'details': book['details']
                })
            except:
                continue

# Process reviews
reviews_by_title = defaultdict(list)
for review in reviews_data:
    if review.get('title'):
        reviews_by_title[review['title']].append(float(review['rating']))

print('__RESULT__:')
print(json.dumps({
    'books_with_year_count': len(books_with_years),
    'unique_books_in_reviews': len(reviews_by_title),
    'sample_books': books_with_years[:3],
    'sample_reviews': list(reviews_by_title.items())[:2]
}))"}

{"code": "import json
import re
from collections import defaultdict

# Load all books and reviews data from storage
books_file_path = locals()['var_functions.query_db:26']
reviews_file_path = locals()['var_functions.query_db:34']

# Read the JSON files
with open(books_file_path, 'r') as f:
    books_info = json.load(f)

with open(reviews_file_path, 'r') as f:
    reviews_data = json.load(f)

# Process to find publication years from book details
books_with_years = []
year_pattern = re.compile(r'(19|20)\d{2}')

for book in books_info:
    if book.get('details'):
        matches = year_pattern.findall(book['details'])
        if matches:
            try:
                year = int(matches[0])
                decade = (year // 10) * 10
                books_with_years.append({
                    'book_id': book['book_id'],
                    'title': book['title'],
                    'year': year,
                    'decade': decade
                })
            except:
                continue

# Group reviews by title and calculate averages
reviews_by_title = defaultdict(list)
for review in reviews_data:
    if review.get('title'):
        try:
            rating = float(review['rating'])
            reviews_by_title[review['title']].append(rating)
        except:
            continue

print('__RESULT__:')
print(json.dumps({
    'books_with_year_count': len(books_with_years),
    'books_with_years_sample': books_with_years[:5],
    'reviews_by_title_count': len(reviews_by_title),
    'reviews_samples': dict(list(reviews_by_title.items())[:2])
}))"}

